"use strict";(self.webpackChunkwebsite=self.webpackChunkwebsite||[]).push([[60042],{6224:(e,i,t)=>{t.r(i),t.d(i,{assets:()=>c,contentTitle:()=>o,default:()=>h,frontMatter:()=>s,metadata:()=>a,toc:()=>d});const a=JSON.parse('{"id":"Preface End facism/eos/EO_14385_Pty_Threats_gpt-5-mini_20260306_120153","title":"EO 14385 Protecting the National Security and Welfare of the United States and Its Citizens From Criminal Actors and Other Public Safety Threats","description":"Table of Contents: Executive summary and principal findings; Text and immediate legal footing of EO 14385; What the order formally requires versus how it operates in practice; Policy mechanisms and administrative pathways the order triggers; Who benefits and who bears the costs; Institutional, constitutional, regulatory, and economic implications; Litigation exposure, legal durability, and reversal pathways; Implementation feasibility, agency capacity, and budget effects; Second\u2011order consequences, risks, and likely abuses; Corruption and self\u2011dealing scenarios (speculative); Conclusion and urgent recommendations.","source":"@site/docs/1. Preface End facism/eos/EO_14385_Pty_Threats_gpt-5-mini_20260306_120153.md","sourceDirName":"1. Preface End facism/eos","slug":"/Preface End facism/eos/EO_14385_Pty_Threats_gpt-5-mini_20260306_120153","permalink":"/firstpub-Platform/docs/Preface End facism/eos/EO_14385_Pty_Threats_gpt-5-mini_20260306_120153","draft":false,"unlisted":false,"editUrl":"https://github.com/unitedprogressparty/firstpub-Platform/tree/main/docs/1. Preface End facism/eos/EO_14385_Pty_Threats_gpt-5-mini_20260306_120153.md","tags":[],"version":"current","frontMatter":{"title":"EO 14385 Protecting the National Security and Welfare of the United States and Its Citizens From Criminal Actors and Other Public Safety Threats"},"sidebar":"tutorialSidebar","previous":{"title":"EO 14380 Addressing Threats to the United States by the Government of Cuba","permalink":"/firstpub-Platform/docs/Preface End facism/eos/EO_14380_Ant_ofCuba_gpt-5-mini_20260307_111258"},"next":{"title":"Executive Order 14385 \u2014 Protecting the National Security and Welfare of the United States and Its Citizens From Criminal Actors and Other Public Safety Threats","permalink":"/firstpub-Platform/docs/Preface End facism/eos/EO_14385_Pty_Threats_gpt-5-mini_20260306_161803"}}');var n=t(74848),r=t(28453);const s={title:"EO 14385 Protecting the National Security and Welfare of the United States and Its Citizens From Criminal Actors and Other Public Safety Threats"},o="Executive Order 14385 \u2014 Protecting the National Security and Welfare of the United States and Its Citizens From Criminal Actors and Other Public Safety Threats",c={},d=[{value:"Executive summary and principal findings",id:"executive-summary-and-principal-findings",level:2},{value:"Text and immediate legal footing of EO 14385",id:"text-and-immediate-legal-footing-of-eo-14385",level:2},{value:"What the order formally states and how it operates in practice",id:"what-the-order-formally-states-and-how-it-operates-in-practice",level:2},{value:"Policy language decoded and the mechanisms the order sets in motion",id:"policy-language-decoded-and-the-mechanisms-the-order-sets-in-motion",level:2},{value:"Who benefits and who bears the costs",id:"who-benefits-and-who-bears-the-costs",level:2},{value:"Institutional, constitutional, and regulatory implications",id:"institutional-constitutional-and-regulatory-implications",level:2},{value:"Litigation exposure, legal durability, and reversal pathways",id:"litigation-exposure-legal-durability-and-reversal-pathways",level:2},{value:"Implementation feasibility, agency capacity, and procedural requirements",id:"implementation-feasibility-agency-capacity-and-procedural-requirements",level:2},{value:"Fiscal and economic impacts (quantification where possible) and resource implications",id:"fiscal-and-economic-impacts-quantification-where-possible-and-resource-implications",level:2},{value:"Anticipated second\u2011order effects, unintended consequences, and spillovers",id:"anticipated-secondorder-effects-unintended-consequences-and-spillovers",level:2},{value:"Harms and risks with specificity and substantiation",id:"harms-and-risks-with-specificity-and-substantiation",level:2},{value:"Downstream developments in the policy area and relevant precedents",id:"downstream-developments-in-the-policy-area-and-relevant-precedents",level:2},{value:"Corruption, bribery, and self\u2011dealing: speculative worst\u2011case scenarios",id:"corruption-bribery-and-selfdealing-speculative-worstcase-scenarios",level:2},{value:"Conclusion and urgent recommendations",id:"conclusion-and-urgent-recommendations",level:2}];function l(e){const i={a:"a",h1:"h1",h2:"h2",header:"header",p:"p",...(0,r.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(i.header,{children:(0,n.jsx)(i.h1,{id:"executive-order-14385--protecting-the-national-security-and-welfare-of-the-united-states-and-its-citizens-from-criminal-actors-and-other-public-safety-threats",children:"Executive Order 14385 \u2014 Protecting the National Security and Welfare of the United States and Its Citizens From Criminal Actors and Other Public Safety Threats"})}),"\n",(0,n.jsx)(i.p,{children:"Table of Contents: Executive summary and principal findings; Text and immediate legal footing of EO 14385; What the order formally requires versus how it operates in practice; Policy mechanisms and administrative pathways the order triggers; Who benefits and who bears the costs; Institutional, constitutional, regulatory, and economic implications; Litigation exposure, legal durability, and reversal pathways; Implementation feasibility, agency capacity, and budget effects; Second\u2011order consequences, risks, and likely abuses; Corruption and self\u2011dealing scenarios (speculative); Conclusion and urgent recommendations."}),"\n",(0,n.jsx)(i.h2,{id:"executive-summary-and-principal-findings",children:"Executive summary and principal findings"}),"\n",(0,n.jsxs)(i.p,{children:["Executive Order 14385, signed February 6, 2026, commands the Attorney General to provide the Department of Homeland Security (DHS) \u201caccess, for purposes related to DHS\u2019s screening and vetting missions and to the maximum extent permitted by law, to criminal history record information (CHRI) available to or maintained by the Department of Justice.\u201d The Order also authorizes DHS to exchange felony conviction records with Visa Waiver Program (VWP) states, nations that have entered into \u201cPreventing and Combating Serious Crime\u201d or similar agreements with the United States, and \u201cother trusted allies,\u201d on a reciprocal, agreement\u2011by\u2011agreement basis that the EO describes as subject to privacy safeguards. The White House and the Federal Register text are consistent and clear as primary sources. (",(0,n.jsx)(i.a,{href:"https://www.whitehouse.gov/presidential-actions/2026/02/protecting-the-national-security-and-welfare-of-the-united-states-and-its-citizens-from-criminal-actors-and-other-public-safety-threats/?utm_source=openai",children:"whitehouse.gov"}),")"]}),"\n",(0,n.jsxs)(i.p,{children:["The EO\u2019s text is short and framed as administrative coordination, but its practical reach is expansive. By directing DOJ to give DHS the CHRI it \u201cmay provide\u201d under existing law and by greenlighting reciprocal exchanges with foreign partners, the Order attempts to institutionalize broad federated and international access to sensitive criminal records for immigration screening. The Order is not itself a statute and explicitly disclaims creating judicially enforceable rights; nevertheless, its central commands push agencies to stretch regulatory and intergovernmental authorities and to operationalize cross\u2011system data sharing that raises acute privacy, civil\u2011liberties, and geopolitical risks. (",(0,n.jsx)(i.a,{href:"https://public-inspection.federalregister.gov/2026-02819.pdf",children:"public-inspection.federalregister.gov"}),")"]}),"\n",(0,n.jsxs)(i.p,{children:["This report finds that the Order is functionally designed to expand executive capacity to aggregate, analyze, and share CHRI for immigration and border screening, and to press foreign partners into reciprocal data arrangements as a condition of program participation or favor. That expansion will benefit federal immigration and enforcement actors and political constituencies prioritizing heightened immigration enforcement. It will impose costs on immigrants and travelers, on privacy and civil\u2011liberty norms, on historically over\u2011policed communities, and on allied nations whose citizens may be subject to intrusive U.S. queries. The EO is exposed to predictable legal challenge under the Privacy Act, the Administrative Procedure Act (APA), statutory limits governing CHRI dissemination (including Title 28 and the CJIS framework), and constitutional doctrines when implementation chills protected speech or association. Prior administrative drives to centralize and access Americans\u2019 personal data have prompted litigation and have been enjoined in other contexts; the legal architecture that regulates CHRI is complex and will constrain\u2014but not necessarily prevent\u2014the EO\u2019s operational ambitions. (",(0,n.jsx)(i.a,{href:"https://public-inspection.federalregister.gov/2026-02819.pdf",children:"public-inspection.federalregister.gov"}),")"]}),"\n",(0,n.jsx)(i.h2,{id:"text-and-immediate-legal-footing-of-eo-14385",children:"Text and immediate legal footing of EO 14385"}),"\n",(0,n.jsxs)(i.p,{children:["The Executive Order is two substantive paragraphs long in its operative sections. Section 2 orders the Attorney General to grant DHS access to CHRI in DOJ custody \u201cto the maximum extent permitted by law\u201d for DHS screening and vetting missions. Section 3 authorizes the Secretary of Homeland Security to exchange CHRI with VWP countries and other \u201ctrusted allies\u201d on the basis of reciprocity and under DHS agreements that \u201ccontain appropriate safeguards\u201d to protect United States persons and other individuals, and to use that information \u201cfor the sole purpose of screening travelers and immigrants seeking to enter or stay\u201d in partner countries. The EO cites 6 U.S.C. 122(a)(2) as part of its authority and otherwise leaves agencies to effectuate the directives \u201cconsistent with applicable law and subject to the availability of appropriations.\u201d The published Federal Register entry is the authoritative text. (",(0,n.jsx)(i.a,{href:"https://public-inspection.federalregister.gov/2026-02819.pdf",children:"public-inspection.federalregister.gov"}),")"]}),"\n",(0,n.jsxs)(i.p,{children:["That statutory citation (6 U.S.C. 122(a)(2)) ties the Order to existing DHS missions, but it does not supplant detailed statutory and regulatory regimes that govern criminal history data dissemination. Federal criminal history records are primarily governed by the Attorney General\u2019s authorities and by a matrix of statutory provisions, DOJ regulations, and FBI Criminal Justice Information Services (CJIS) policies\u2014principally 28 U.S.C. \xa7 534 (DOJ authority to maintain and exchange criminal identification and related records), Title 28 of the Code of Federal Regulations (Part 20) governing CHRI dissemination, the CJIS Security Policy, and the National Crime Prevention and Privacy Compact. These instruments condition who may receive CHRI, for which purposes, and under what technical and audit requirements. Any DOJ or FBI change to longstanding dissemination practices will need to be reconciled with these preexisting constraints. (",(0,n.jsx)(i.a,{href:"https://www.fbi.gov/how-we-can-help-you/more-fbi-services-and-information/freedom-of-informationprivacy-act/department-of-justice-fbi-privacy-impact-assessments/firs-iafis?utm_source=openai",children:"fbi.gov"}),")"]}),"\n",(0,n.jsx)(i.h2,{id:"what-the-order-formally-states-and-how-it-operates-in-practice",children:"What the order formally states and how it operates in practice"}),"\n",(0,n.jsxs)(i.p,{children:["Formally, EO 14385 reads as an inter\u2011agency instruction requiring DOJ to make available criminal history records to DHS for civil\u2011administrative screening missions and permitting DHS to negotiate reciprocal exchanges with foreign partners. On paper the EO repeatedly conditions action on existing lawful authority, on reciprocity for foreign exchanges, and on \u201cappropriate safeguards.\u201d The White House version reiterates the administration\u2019s framing that the measures are limited to border security and public safety purposes. (",(0,n.jsx)(i.a,{href:"https://www.whitehouse.gov/presidential-actions/2026/02/protecting-the-national-security-and-welfare-of-the-united-states-and-its-citizens-from-criminal-actors-and-other-public-safety-threats/?utm_source=openai",children:"whitehouse.gov"}),")"]}),"\n",(0,n.jsxs)(i.p,{children:["In practice, however, the EO performs three distinct functions. First, it acts as a high\u2011level political signal that pressure\u2011tests the boundaries of DOJ and FBI dissemination policies by urging maximum sharing \u201cpermitted by law.\u201d That signaling changes institutional incentives: DOJ and FBI lawyers will be incentivized to reinterpret Part 20 and CJIS guidance more liberally; DHS will accelerate requests and resource commitments; and partner states will face diplomatic pressure to accept or reciprocate data exchanges as a condition of program inclusion or preferred treatment. Second, the EO lowers the political cost for DHS to seek programmatic access to CHRI and to use CHRI across an expanded set of immigration screening adjudications, making routine previously exceptional uses. Third, the EO creates operational pressure to craft interlocking memoranda of understanding (MOUs), technical interfaces, auditing protocols, and contract vehicles for private vendors that will materially alter who touches sensitive data and under what security regimes. These real\u2011world processes often exceed the cautious constraints suggested by the EO\u2019s text and by the CJIS rules; prior federal pushes to centralize data produced both expanded access and recurring compliance and auditing crises. (",(0,n.jsx)(i.a,{href:"https://www.fbi.gov/how-we-can-help-you/more-fbi-services-and-information/freedom-of-information-privacy-act/department-of-justice-fbi-privacy-impact-assessments/iafis-ngi-biometric-interoperability?utm_source=openai",children:"fbi.gov"}),")"]}),"\n",(0,n.jsx)(i.h2,{id:"policy-language-decoded-and-the-mechanisms-the-order-sets-in-motion",children:"Policy language decoded and the mechanisms the order sets in motion"}),"\n",(0,n.jsxs)(i.p,{children:["The EO\u2019s operative phrase \u201cto the maximum extent permitted by law\u201d is the pivot. That phrase operates as a directive to agency counsel to maximize permissible sharing under current statutory and regulatory doctrines, and to minimize conservative readings that protect privacy. In administrative practice this language will generate internal legal memoranda asserting broad statutory constructions, written justifications to permit expanded CHRI use (for example asserting that \u201cscreening and vetting\u201d fall within established immigration and national\u2011security exceptions), and requests to alter or expand the functional definitions used by CJIS and FBI systems about authorized purposes. The CJIS system requires authorized purpose statements, originating agency identifiers, and technical security agreements. Translating the EO into practice therefore entails procurement work, new ORI codes and audit trails, revisions to system of records notices under the Privacy Act if user scope changes, and likely interagency memoranda that recast DHS roles as \u201ccriminal\u2011justice purpose\u201d actors for CHRI. The DOJ and FBI possess both statutory levers and regulatory discretion that can be deployed; the EO\u2019s plain function is to push them in that direction. (",(0,n.jsx)(i.a,{href:"https://www.fbi.gov/how-we-can-help-you/more-fbi-services-and-information/freedom-of-informationprivacy-act/department-of-justice-fbi-privacy-impact-assessments/firs-iafis?utm_source=openai",children:"fbi.gov"}),")"]}),"\n",(0,n.jsxs)(i.p,{children:["Beyond domestic sharing, Section 3\u2019s international exchange authorization incentivizes DHS to negotiate CHRI\u2011sharing MOUs with VWP members and other \u201ctrusted allies.\u201d The VWP already embeds information\u2011sharing expectations and has historically required Preventing and Combating Serious Crime (PCSC) or equivalent agreements, but those agreements have long suffered from asymmetric capability and reciprocity problems. Converting political pressure into binding foreign\u2011agency data access agreements will involve conditioning program membership or operational privileges on partner nations\u2019 acceptance of U.S. queries, technical compatibility with FBI systems, or direct bilateral access. Such arrangements risk expanding U.S. access to partner police databases and, conversely, enabling foreign governments to seek deeper U.S. access to U.S. data\u2014or to raise human\u2011rights and privacy concerns for migrants and asylum seekers in partner states whose records are more porous or politically manipulated. The operational mechanism thus becomes both data diplomacy and technical integration\u2014each with its own legal and compliance constraints. (",(0,n.jsx)(i.a,{href:"https://www.everycrsreport.com/files/2024-10-15_RL32221_f8450b3ccf5aa6aac9a48bee6afcea181ec28820.pdf?utm_source=openai",children:"everycrsreport.com"}),")"]}),"\n",(0,n.jsx)(i.h2,{id:"who-benefits-and-who-bears-the-costs",children:"Who benefits and who bears the costs"}),"\n",(0,n.jsx)(i.p,{children:"The beneficiaries are intellectually simple to identify: DHS and its component enforcement elements (CBP, USCIS, ICE), DOJ and FBI programs that trade or monetize enforcement cooperation, contractors building the interfaces and analytics (identity verification, biometric matching, database integration), and political constituencies that reward stricter immigration enforcement. Allies amenable to U.S. technical standards and whose political systems privilege cooperation may gain leverage and diplomatic capital. These actors will secure augmented data flows that expand surveillance, enforcement efficiencies, and control over border management decisions."}),"\n",(0,n.jsxs)(i.p,{children:["The costs fall on multiple fronts. For noncitizens and travelers, the expansion of CHRI access and the internationalization of felony records increases the risk of misclassification, detention, denial of admission, and expedited removals on the basis of incomplete, inaccurately transcribed, or foreign\u2011system convictions that cannot be reliably adjudicated in U.S. administrative processes. For citizens and lawful residents whose records may appear in CHRI exchanges (for example where a U.S. person\u2019s name or identifiers are mistakenly matched), the privacy and redress costs are significant; CHRI systems are error\u2011prone and state practices for record correction vary considerably. For civil liberties and minority communities, broader CHRI use is likely to deepen discriminatory enforcement, amplify pretextual stops, and chill associational and expressive activities when activist or migrant communities understand their records are more likely to be queried internationally or used in immigration adjudications. For allied states, these arrangements risk export of U.S. policing standards and data practices that may conflict with partner privacy or human\u2011rights norms. For the public fisc, costs will include engineering, contracting, compliance auditing, CIS system upgrades, training, and legal defense against litigation. (",(0,n.jsx)(i.a,{href:"https://www.fbi.gov/how-we-can-help-you/more-fbi-services-and-information/freedom-of-information-privacy-act/department-of-justice-fbi-privacy-impact-assessments/iafis-ngi-biometric-interoperability?utm_source=openai",children:"fbi.gov"}),")"]}),"\n",(0,n.jsx)(i.h2,{id:"institutional-constitutional-and-regulatory-implications",children:"Institutional, constitutional, and regulatory implications"}),"\n",(0,n.jsxs)(i.p,{children:["Institutionally, EO 14385 centralizes a policy preference for maximal interagency and international data sharing. It encourages legal reinterpretation rather than legislative change, pushing agencies to use existing statutory regimes as permissive scaffolding. That strategy is familiar: when Congress is politically blocked, Administrations use executive direction to remodel administrative practice. The Order therefore risks reconfiguring the baseline operating assumptions of DOJ and DHS and effectively expands executive capacity to assemble cross\u2011domain datasets without new statutory authorization. Where agencies move forward by administrative rule or contractual arrangements with private vendors to operationalize broad CHRI exchange, the move will court sustained oversight and litigation. (",(0,n.jsx)(i.a,{href:"https://www.fbi.gov/how-we-can-help-you/more-fbi-services-and-information/freedom-of-informationprivacy-act/department-of-justice-fbi-privacy-impact-assessments/firs-iafis?utm_source=openai",children:"fbi.gov"}),")"]}),"\n",(0,n.jsxs)(i.p,{children:["Constitutionally, the most immediate risks are tied to privacy, due process, and the potential for viewpoint or association\u2011based chilling effects where CHRI becomes a vehicle for immigration denial or law enforcement surveillance of political actors. While the Fourth Amendment\u2019s protections are centered on search and seizure doctrines, expansive data sharing that facilitates administrative deprivation of liberty (detention or removal) without adequate procedural safeguards raises serious Fifth Amendment due\u2011process questions. The Order\u2019s nonjudicial remedy waiver clause\u2014\u201cnot intended to, and does not, create any right or benefit enforceable at law\u201d\u2014does not insulate implementing agency acts from constitutional or statutory challenge, particularly where agencies engage in rule\u2011making or change system of records notices under the Privacy Act. (",(0,n.jsx)(i.a,{href:"https://public-inspection.federalregister.gov/2026-02819.pdf",children:"public-inspection.federalregister.gov"}),")"]}),"\n",(0,n.jsxs)(i.p,{children:["Regulatory implications run to the heart of DOJ/FBI CJIS controls. Title 28 CFR Part 20 circumscribes dissemination of CHRI, limiting access to criminal justice agencies and specifying permissible noncriminal uses and audit obligations. The CJIS Security Policy imposes strict security and audit obligations for technical participants. To expand DHS access and permit foreign exchanges that are deeper than prior practice, the agencies will likely have to create new CJIS user ORIs, establish security addenda, prepare privacy impact assessments, and possibly amend system of records notices pursuant to the Privacy Act. Each of these steps triggers notice, comment, or inter\u2011agency clearance and thus becomes a potential litigation flashpoint under the APA if agencies are found to have circumvented procedural requirements. (",(0,n.jsx)(i.a,{href:"https://www.fbi.gov/how-we-can-help-you/more-fbi-services-and-information/freedom-of-informationprivacy-act/department-of-justice-fbi-privacy-impact-assessments/firs-iafis?utm_source=openai",children:"fbi.gov"}),")"]}),"\n",(0,n.jsx)(i.h2,{id:"litigation-exposure-legal-durability-and-reversal-pathways",children:"Litigation exposure, legal durability, and reversal pathways"}),"\n",(0,n.jsxs)(i.p,{children:["EO 14385 is susceptible to several predictable legal attack vectors. Plaintiffs can plausibly bring APA claims where agency implementations constitute \u201csignificant\u201d rule changes without required notice and comment, or where agencies fail to prepare system of records notices and adequate Privacy Act compliance. Privacy Act challenges may arise if interagency sharing is broadened without required notice and limits. Constitutional claims under the Fifth Amendment may be litigated where administrative uses of CHRI produce deprivation without adequate process, or where enforcement disproportionately targets protected classes. The administration\u2019s prior data\u2011centralization efforts have already produced litigation and injunctions in related domains, demonstrating a litigation environment predisposed to challenge such expansions. In other recent cases involving aggressive executive action, courts have issued preliminary relief when plaintiffs demonstrated likelihood of constitutional and statutory harms. These precedents make litigation a realistic and likely check on administrative overreach, even if courts ultimately allow some forms of sharing. (",(0,n.jsx)(i.a,{href:"https://www.democracydocket.com/news-alerts/trump-administration-sued-over-massive-interagency-database-of-americans-private-information/?utm_source=openai",children:"democracydocket.com"}),")"]}),"\n",(0,n.jsxs)(i.p,{children:["A subsequent administration that sought to reverse EO 14385 can do so through multiple concrete pathways. The simplest and fastest is to rescind the Executive Order and to instruct agencies to suspend any new MOUs or technical integrations. Rescission would not automatically unwind already\u2011executed agreements or technical changes, so subsequent actions should include revoking agency directives, terminating MOUs that exceed statutory authority, directing the FBI and DOJ to freeze new CHRI dissemination authorizations, and directing DHS to halt foreign CHRI exchanges pending statutory authorization. Longer\u2011term reversal tools include withdrawing appropriations for new interfaces, reasserting conservative CJIS access standards, and supporting litigation defenses that protect privacy. Congress can also pass targeted legislation to block certain disclosures or to require judicial warrants or specific statutory procedures before CHRI can be used for immigration removal. Each of these pathways has precedent and is viable; legal undoing will require coordinated executive, legislative, and\u2014if necessary\u2014judicial steps. (",(0,n.jsx)(i.a,{href:"https://www.fbi.gov/how-we-can-help-you/more-fbi-services-and-information/freedom-of-information-privacy-act/department-of-justice-fbi-privacy-impact-assessments/iafis-ngi-biometric-interoperability?utm_source=openai",children:"fbi.gov"}),")"]}),"\n",(0,n.jsx)(i.h2,{id:"implementation-feasibility-agency-capacity-and-procedural-requirements",children:"Implementation feasibility, agency capacity, and procedural requirements"}),"\n",(0,n.jsxs)(i.p,{children:["Operationalizing the EO implicates significant technical, personnel, and compliance tasks. The FBI\u2019s CJIS and associated systems (IAFIS/NGI, NCIC, Interstate Identification Index) are not open, frictionless databases that can be simply \u201cswitched\u201d to grant new access. They require originating agency identifiers (ORIs), security addenda, CJIS security vetting of personnel, defined authorized purposes, and auditable interfaces. DHS entities seeking CHRI must obtain CJIS authorization, implement robust information security controls, and accept periodic audits. Where private contractors are used to build or host interfaces, careful contracting and security addenda must be negotiated and monitored. These processes take months to years depending on scale. The EO places the fiscal and publishing cost for itself on DHS, but significant upfront funds will be required to engineer secure, compliant interfaces and to staff expanded vetting operations. DHS has previously estimated large costs for biometrics collection, processing, and system upgrades in other rulemakings, indicating the potential scale of fiscal impact. (",(0,n.jsx)(i.a,{href:"https://www.fbi.gov/how-we-can-help-you/more-fbi-services-and-information/freedom-of-information-privacy-act/department-of-justice-fbi-privacy-impact-assessments/iafis-ngi-biometric-interoperability?utm_source=openai",children:"fbi.gov"}),")"]}),"\n",(0,n.jsxs)(i.p,{children:["Procedurally, many concrete steps implicated by the EO will trigger statutorily imposed administrative obligations. System of records changes under the Privacy Act require public notice and an opportunity for comment where systems of records are significantly changed. Substantive rules to implement new statutory or regulatory obligations require notice and comment unless agencies claim an exception for matters of national security\u2014an exception that will itself be litigated if overused. Agencies are also required to coordinate with OMB on privacy and data\u2011sharing policies, to prepare privacy impact assessments, and to consult with Congress in circumstances where statutory authority or appropriations may be implicated. Failure to follow those procedural guardrails is a predictable basis for successful litigation. (",(0,n.jsx)(i.a,{href:"https://law.justia.com/cases/federal/district-courts/district-of-columbia/dcdce/1%3A2025cv00946/279032/236/?utm_source=openai",children:"law.justia.com"}),")"]}),"\n",(0,n.jsx)(i.h2,{id:"fiscal-and-economic-impacts-quantification-where-possible-and-resource-implications",children:"Fiscal and economic impacts (quantification where possible) and resource implications"}),"\n",(0,n.jsxs)(i.p,{children:["EO 14385\u2019s text contains one narrow fiscal allocation clause\u2014the costs for publication of the Order shall be borne by DHS\u2014but it does not estimate the realoperational fiscal consequences. Quantifying full budgetary impact requires modeling expenditures for system integration, personnel, CJIS compliance, contracting, audits, training, and legal defense against likely litigation. Historic DHS rulemakings and biometric initiatives provide useful analogues: the DHS rulemaking on biometrics and employment authorization included detailed, multi\u2011billion dollar estimates and revealed that major biometric and screening changes can involve tens of millions to billions of dollars in additional program costs when aggregated across operations, travel, and processing burdens. These precedents show the EO could easily create multi\u2011year, multi\u2011hundred\u2011million dollar\u2014potentially multi\u2011billion dollar\u2014commitments if DHS opts for broad implementation across immigration adjudications and if a network of international exchanges is pursued. Moreover, indirect economic costs will include delays and processing backlogs that translate into higher administrative costs, potential labor market impacts where work authorization is delayed or denied, and the need for state and local actors to process or respond to federal requests. The EO\u2019s narrow publication cost clause is therefore materially misleading as an indicator of the action\u2019s fiscal modesty. (",(0,n.jsx)(i.a,{href:"https://regulations.justia.com/regulations/fedreg/2026/02/23/2026-03595.html?utm_source=openai",children:"regulations.justia.com"}),")"]}),"\n",(0,n.jsx)(i.h2,{id:"anticipated-secondorder-effects-unintended-consequences-and-spillovers",children:"Anticipated second\u2011order effects, unintended consequences, and spillovers"}),"\n",(0,n.jsxs)(i.p,{children:["Several predictable second\u2011order effects should be anticipated. First, data asymmetry: the U.S. may press partners to provide detailed police and conviction data while refusing broad reciprocal access or judicial protections, creating inequities and diplomatic friction. European partners in particular have resisted unconditional reciprocity because of privacy protections\u2014and past negotiations over VWP reciprocity have stalled over precisely these imbalances. Second, error cascades: CHRI systems contain transcription errors, differences in conviction nomenclature, and jurisdictional disparities that when ported into immigration decisionmaking produce erroneous denials, detention, or removal risks. Third, geopolitical misuse: where the U.S. relies on partner states with weak rule-of-law or repressive record\u2011keeping, the lists exchanged could be weaponized by partner regimes to target dissidents who might be mistaken for criminal actors, or conversely, the U.S. could become complicit in foreign human\u2011rights abuses through data sharing. Fourth, expanding databases incentivize mission creep: once agencies build the technical means to aggregate and match records at scale, political pressure to use those capabilities for additional enforcement or domestic surveillance tasks will follow. Finally, market distortions will flow to private contractors who build and operate interoperability and analytics layers; this creates new rent\u2011seeking incentives and privatized surveillance ecosystems that are inherently difficult to oversee. These second\u2011order dynamics are not speculative: advocacy groups and independent trackers have repeatedly warned against federal demands for access to partner police databases and have documented the risky incentives that follow. (",(0,n.jsx)(i.a,{href:"https://www.statewatch.org/news/2023/november/usa-seeks-bilateral-deals-for-access-to-european-criminal-terrorist-and-identity-records/?utm_source=openai",children:"statewatch.org"}),")"]}),"\n",(0,n.jsx)(i.h2,{id:"harms-and-risks-with-specificity-and-substantiation",children:"Harms and risks with specificity and substantiation"}),"\n",(0,n.jsxs)(i.p,{children:["The most acute harms are concrete and measurable. Administrative denials of admission and expedited removals that rely on foreign conviction data are immediate harms that can be counted in denied entries and removal orders. CHRI misidentification produces wrongful detentions; even short detentions impose economic harms in lost wages and legal costs and inflict reputational and psychological injuries. The expansion of CHRI exchange will disproportionally affect migrants from countries with aggressive policing, weak record\u2011correction mechanisms, or where convictions are politically motivated\u2014making certain nationalities or ethnic groups more vulnerable to administrative exclusion. The erosion of privacy norms for U.S. citizens is also measurable: broader CHRI queries increase the risk that U.S. persons will have their names checked against foreign databases and erroneously flagged, creating secondary burdens in administrative clearance times and litigation to correct records. The cumulative threat to democratic safeguards\u2014where executive power is used to build large, searchable datasets about millions of individuals with limited independent oversight\u2014adds systemic risk that may be realized in political weaponization of data or in chilling of civil society. These are not abstract possibilities but predictable outcomes of a policy that normalizes expansive data sharing for enforcement purposes. (",(0,n.jsx)(i.a,{href:"https://www.fbi.gov/how-we-can-help-you/more-fbi-services-and-information/freedom-of-information-privacy-act/department-of-justice-fbi-privacy-impact-assessments/iafis-ngi-biometric-interoperability?utm_source=openai",children:"fbi.gov"}),")"]}),"\n",(0,n.jsx)(i.h2,{id:"downstream-developments-in-the-policy-area-and-relevant-precedents",children:"Downstream developments in the policy area and relevant precedents"}),"\n",(0,n.jsxs)(i.p,{children:["This EO sits in a pattern of recent executive actions pushing for broader inter\u2011agency data access and foreign data exchanges tied to immigration and national\u2011security imperatives. Prior rulemakings and EOs have similarly prioritized data centralization, biometrics expansion, and foreign data agreements. For example, DHS rulemakings late in 2025 and in 2026 on biometric collection and refugee/asylum processing show the department\u2019s trajectory toward automated foreign CHRI queries for adjudications and highlight large fiscal and administrative footprints. Advocacy groups have already sued to block federal data centralization projects in related domains, and civil\u2011liberties organizations have flagged the same risks EO 14385 advances. These downstream developments demonstrate both implementational feasibility (agency willingness to invest) and litigation risk (civil\u2011society readiness to sue). In short, EO 14385 is part of a sustained push rather than an isolated incident, and the same actors, processes, and legal battlegrounds will shape its aftermath. (",(0,n.jsx)(i.a,{href:"https://regulations.justia.com/regulations/fedreg/2026/02/23/2026-03595.html?utm_source=openai",children:"regulations.justia.com"}),")"]}),"\n",(0,n.jsx)(i.h2,{id:"corruption-bribery-and-selfdealing-speculative-worstcase-scenarios",children:"Corruption, bribery, and self\u2011dealing: speculative worst\u2011case scenarios"}),"\n",(0,n.jsxs)(i.p,{children:["Executive power over sensitive data, procurement, and foreign arrangement leverage creates fertile ground for corruption if institutional safeguards are eroded. One plausible path to self\u2011dealing is the creation of no\u2011bid or sole\u2011source contracts to build CHRI interconnectivity platforms and analytics layers where decisionmakers award lucrative contracts to firms connected to officials, their families, or political allies. A narrow set of contractors could win multi-year, multi\u2011hundred\u2011million dollar service agreements without transparent procurement if the administration asserts national\u2011security exceptions. These contractors could then subcontract to shell companies or distribute kickbacks in the form of consulting fees, board seats, or equity stakes to officials or their relatives. Alternatively, foreign MOUs awarding privileged access could be conditioned informally on procurement relationships or post\u2011MOU business favors to foreign entities that are intermediaries for U.S. firms or officials\u2019 associates. Another form of political corruption is the instrumentalized use of CHRI data to harm political opponents\u2014selectively leaking derogatory criminal records, flagging opponents for administrative actions, or prioritizing enforcement against politically inconvenient groups under the veneer of \u201cscreening.\u201d The EO\u2019s design\u2014delegating large discretion to DOJ and DHS and encouraging private contracts for technical work\u2014creates multiple attractive vectors for bribery, embezzlement, nepotism, and transactional diplomacy if oversight is weak. The worst conceivable abuses include funneling no\u2011bid contracts tied to MOUs into private entities controlled by insiders, awarding foreign\u2011access privileges in exchange for campaign or personal favors, and using enriched datasets to pursue targeted political retribution\u2014each of which would be criminal, corrosive of democratic norms, and difficult to unwind absent robust oversight and criminal enforcement. These are hypothetical but realistic abuses that follow logically from the convergence of concentrated executive discretion, opaque procurement, private contractor dependence, and cross\u2011border bargains the EO implicitly encourages. (",(0,n.jsx)(i.a,{href:"https://www.fbi.gov/how-we-can-help-you/more-fbi-services-and-information/freedom-of-information-privacy-act/department-of-justice-fbi-privacy-impact-assessments/iafis-ngi-biometric-interoperability?utm_source=openai",children:"fbi.gov"}),")"]}),"\n",(0,n.jsx)(i.h2,{id:"conclusion-and-urgent-recommendations",children:"Conclusion and urgent recommendations"}),"\n",(0,n.jsx)(i.p,{children:"Executive Order 14385 is presented as a narrow administrative coordination measure, but in context it is a strategic lever to expand executive authority over sensitive criminal records domestically and internationally. Its plain wording funnels agencies toward maximal sharing, and its practical effect will be to create durable technical, diplomatic, and contractual architectures that normalize expanded surveillance of migrants, travelers, and\u2014through misidentification risks\u2014U.S. persons. The harms to privacy, due process, and vulnerable communities are real and measurable; litigation and legislative pushback are likely and sensible checks."}),"\n",(0,n.jsxs)(i.p,{children:["Urgent recommendations for opponents and for any subsequent administration seeking to mitigate harm include immediate suspension of new MOUs and technical integrations pending Privacy Act and CJIS review; imposing a moratorium on new procurement related to CHRI exchange unless subject to transparent competitive processes; requiring public Privacy Impact Assessments and system of records notices before any new dissemination begins; instituting external audits and Congress\u2011mandated reporting on any data transfers and on error\u2011correction mechanisms; and, where appropriate, rescinding the EO and restoring conservative CJIS access standards. Congress should consider clarifying statutory limits on domestic and foreign CHRI dissemination and demanding express legislative authorization for any international exchanges that exceed current Compact or VWP frameworks. Civil society should be resourced to litigate procedural defects promptly, and federal courts should insist on the procedural safeguards the Privacy Act and APA require. The stakes\u2014privacy, rule of law, and protection against the weaponization of personal data\u2014are too high to be resolved through opaque, accelerated implementation. (",(0,n.jsx)(i.a,{href:"https://public-inspection.federalregister.gov/2026-02819.pdf",children:"public-inspection.federalregister.gov"}),")"]}),"\n",(0,n.jsxs)(i.p,{children:["This report has relied on the Executive Order as published in the Federal Register and on official White House text for the EO\u2019s language, and it has situated the Order against primary statutory and regulatory materials governing criminal history data, the FBI CJIS framework, Visa Waiver Program policy, and recent agency and civil\u2011society responses to related federal data\u2011access initiatives. The analysis identifies probable administrative pathways by which the EO will be operationalized, quantifies the categories of fiscal exposure and social cost, and maps realistic legal and political avenues to reverse or constrain unlawful or harmful implementation. The described harms are grounded in regulatory text and in contemporaneous reporting and oversight litigation that document both the administration\u2019s track of similar actions and the predictable legal friction those actions create. (",(0,n.jsx)(i.a,{href:"https://public-inspection.federalregister.gov/2026-02819.pdf",children:"public-inspection.federalregister.gov"}),")"]})]})}function h(e={}){const{wrapper:i}={...(0,r.R)(),...e.components};return i?(0,n.jsx)(i,{...e,children:(0,n.jsx)(l,{...e})}):l(e)}},28453:(e,i,t)=>{t.d(i,{R:()=>s,x:()=>o});var a=t(96540);const n={},r=a.createContext(n);function s(e){const i=a.useContext(r);return a.useMemo((function(){return"function"==typeof e?e(i):{...i,...e}}),[i,e])}function o(e){let i;return i=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:s(e.components),a.createElement(r.Provider,{value:i},e.children)}}}]);